'use strict';
class UsernameValidator{
static#instance=null;
#input;
#status;#abort=new AbortController();#checkController=null;#debounceId=0;#generation=0;#lastValid='';
constructor(input,status){
this.#input=input;
this.#status=status;
const{signal}=this.#abort;
input.addEventListener('input',this.#handleInput,{signal});
input.addEventListener('blur',this.#handleBlur,{signal});
input.addEventListener('invalid',this.#handleInvalid,{signal});
if(input.value)this.#evaluate();}
static init(){
if(UsernameValidator.#instance)return UsernameValidator.#instance;
const input=document.getElementById('username');
const status=document.querySelector('[data-username-status]');
if(!input||!status)return null;
return(UsernameValidator.#instance=new UsernameValidator(input,status));}
destroy(){
this.#abort.abort();
this.#checkController?.abort();
UsernameValidator.#instance=null;}#handleInput=()=>{
const lower=this.#input.value.toLowerCase();
if(this.#input.value!==lower){
const pos=this.#input.selectionStart;
this.#input.value=lower;
if(pos!==null)this.#input.setSelectionRange(pos,pos);}
this.#evaluate();};#handleBlur=()=>{
if(this.#input.value&&!this.#input.checkValidity()){
this.#input.reportValidity();}};#handleInvalid=(e)=>{
e.preventDefault();
this.#evaluate();
this.#input.reportValidity();};
#checkLocal(){
const v=this.#input.value;
if(v==='')return'Username is required.';
if(v.length<3)return`Add ${3 - v.length} more character${3 - v.length === 1 ? '' : 's'}.`;
if(v.length>30)return'Username must be 30 characters or fewer.';
if(!/^[a-z]/.test(v))return'Must start with a lowercase letter.';
if(!/[a-z0-9]$/.test(v))return'Must end with a letter or number — no trailing . _ or -';
if(!/^[a-z0-9._-]+$/.test(v))return'Only lowercase letters, numbers, periods, hyphens, or underscores.';
return'';}#evaluate(){
clearTimeout(this.#debounceId);
this.#checkController?.abort();
const value=this.#input.value;
const localError=this.#checkLocal();
if(localError){
this.#input.setCustomValidity(localError);
this.#renderStatus('error',localError);
this.#lastValid='';
return;}
this.#input.setCustomValidity('');
if(value===this.#lastValid)return;
this.#renderStatus('checking','Checking availability\u2026');
this.#debounceId=window.setTimeout(()=>this.#fetchAvailability(value),350);}
async#fetchAvailability(value){
const token=++this.#generation;
this.#checkController=new AbortController();
try{
const res=await NT.fetch(`/api/check-username?u=${encodeURIComponent(value)}`,{
signal:this.#checkController.signal,});
if(token!==this.#generation)return;
if(!res.ok){
this.#renderStatus('idle','');
return;}
const{status}=await res.json();
if(status==='taken'){
this.#input.setCustomValidity('That username is already taken.');
this.#renderStatus('error','That username is already taken.');
this.#lastValid='';}else if(status==='available'){
this.#input.setCustomValidity('');
this.#renderStatus('ok',`\u201c${value}\u201d is available.`);
this.#lastValid=value;}else{
this.#renderStatus('idle','');
this.#lastValid='';}}catch(err){
if(err?.name==='AbortError')return;
this.#renderStatus('idle','');}}
#renderStatus(state,message){
if(!message){
this.#status.hidden=true;
this.#status.textContent='';
this.#status.removeAttribute('data-state');
this.#status.removeAttribute('role');
return;}
this.#status.hidden=false;
this.#status.textContent=message;
this.#status.setAttribute('data-state',state);
this.#status.setAttribute('role',state==='error'?'alert':'status');}}
UsernameValidator.init();